+struct RestoreGuardView<'a> {
+    request: &'a RestoreRequestRecord,
+    status: Option<&'a RestoreStatusRecord>,
+    now: UnixMillis,
+    heartbeat_stale: bool,
+    terminal: bool,
+    orphaned: bool,
