+fn sanitize_component(raw: &str) -> String {
+    let mut safe: String = raw
+        .chars()
+        .map(|ch| {
+            if ch.is_ascii_alphanumeric() || ch == '-' || ch == '_' {
+                ch
+            } else {
+                '-'
+            }
+        })
+        .collect();
+    if safe.is_empty() {
+        safe = "unknown".to_string();
+    }
+    safe
