+#[derive(Debug, Error)]
+pub(crate) enum LogError {
+    #[error("json serialize failed: {0}")]
+    Json(String),
+    #[error("sink write failed: {0}")]
+    SinkIo(String),
+}
+
+#[derive(Debug, Error)]
+pub(crate) enum LogBootstrapError {
